		assert.equal(input.value, 'initial');

		// First input: type "test"
		input.value = 'test';
		input.dispatchEvent(new InputEvent('input', { bubbles: true }));
		flushSync();

		// Bug: The value should update immediately, not on the second input
		assert.htmlEqual(div.innerHTML, 'test');
		assert.equal(input.value, 'test');

		// Second input: type "test2"
		input.value = 'test2';
		input.dispatchEvent(new InputEvent('input', { bubbles: true }));
		flushSync();

		assert.htmlEqual(div.innerHTML, 'test2');
		assert.equal(input.value, 'test2');
	}
});

