   404→			for (const fn of this.#callbacks) {
   405→				fn();
   406→			}
   407→		}
   408→
   409→		this.#callbacks.clear();
   410→	}
   411→
   412→	increment() {
   413→		this.#pending += 1;
   414→	}
   415→
   416→	decrement() {
   417→		this.#pending -= 1;
