import { flushSync } from 'svelte';
import { test } from '../../test';

export default test({
	test({ assert, target }) {
		const [p, input] = target.querySelectorAll('p, input');

		// Initial state
		assert.htmlEqual(p.innerHTML, '2');
		assert.equal(input.value, '2');

		// Input a value below min
		input.focus();
		input.value = '1';
		input.dispatchEvent(new InputEvent('input', { bubbles: true }));
		flushSync();

		// Validation should update the input immediately back to min value
		assert.equal(input.value, '2');
		assert.htmlEqual(p.innerHTML, '2');

		// Input a valid value
		input.value = '3';
		input.dispatchEvent(new InputEvent('input', { bubbles: true }));
		flushSync();

		assert.equal(input.value, '3');
		assert.htmlEqual(p.innerHTML, '3');

		// Input a value above max
		input.value = '10';
		input.dispatchEvent(new InputEvent('input', { bubbles: true }));
		flushSync();

		// Validation should update the input immediately back to max value
		assert.equal(input.value, '5');
		assert.htmlEqual(p.innerHTML, '5');
	}
});

